window.__QUIZ_DATA__=[{"id":"objective>Physics>2008>1","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : EFFECTS OF HEAT ON MATTER","question":"If the air inside a rigid box is heated, the   I. average speed of the molecules increases  II. pressure of the air increases  III. average separation of the molecules increases.    Which of the statements above are correct?","images":[],"options":{"A":"I and II only","B":"III only","C":"II and III only","D":"I, II and III"},"answer":"A","explanation":"If the air is heated, the average speed of the molecules increase and the pressure of the air will also increase.  N.B: When a gas is heated, the number of collisions of the molecules of the gas usually increases.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>2","subject":"Physics","year":"2008","type":"Objective","topic":"FUNDAMENTAL AND DERIVED QUANTITIES AND UNITS : FUNDAMENTAL QUANTITIES AND UNITS","question":"Which of the following sets of quantities is fundamental?","images":[],"options":{"A":"Length, mass and time","B":"Speed, length and time","C":"Speed, mass and distance","D":"Distance, speed and time"},"answer":"A","explanation":"The fundamental quantities in physics are length, mass and time. These are the basic units from which other units are derived. Speed, distance and pressure are derived quantities.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>3","subject":"Physics","year":"2008","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: ARCHIMEDES\u2019 PRINCIPLE","question":"The diagram above illustrates a Hare's apparatus, e1, e2 represent densities and h1, h2 heights of column of liquids. Which of the following equations is correct?","images":["data:image/png;base64,"],"options":{"A":"h1=h2e1e2","B":"h1=h2e2e1","C":"h1=e1e2h2","D":"h1=e1h2e2"},"answer":"B","explanation":"It should be noted that the pressure on both sides are equal;  i.e P1 = P2  Recall:   P = \u03c1gh  \u2234 P1 = P2 becomes \u03c11gh1 = \u03c12gh2  \u2234 \u03c11h1 = \u03c12h2  h1=\u03c12h2h1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>4","subject":"Physics","year":"2008","type":"Objective","topic":"FLUID AT REST : EQUILIBRIUM OF BODIES: LAW OF FLOTATION","question":"Which of the statements about Archimedes' principle is correct? The upthrust on a body is a measure of the","images":[],"options":{"A":"mass of fluid displaced","B":"weight of the body","C":"volume of the body","D":"weight of the fluid displaced"},"answer":"D","explanation":"Archimede's principle holds that when an object is partially or totally immersed in a fluid, it experiences a loss of weight (upthrust) which is equal to the weight of the fluid displaced.  \u2234 Upthrust is a measure of the weight of the fluid displaced.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>5","subject":"Physics","year":"2008","type":"Objective","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Which of the following is/are in random motion?   I. Pollen grains in water  II. The molecules of hydrogen gas  III. Fine chalk particles floating in air","images":[],"options":{"A":"I and II only","B":"I and III only","C":"II and III only","D":"I, II and III"},"answer":"D","explanation":"Random motion refers to the unpredictable, erratic movement of particles. Pollen grains in water, molecules of hydrogen gas, and fine chalk particles floating in air all exhibit random motion due to the constant, random collisions they undergo with other particles.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>6","subject":"Physics","year":"2008","type":"Objective","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"A car travelling with a uniform velocity of 30ms-1 along a horizontal road overcomes a constant frictional force of 600N. Calculate the power of the engine of the car.","images":[],"options":{"A":"18kW","B":"20kW","C":"180kW","D":"200kW"},"answer":"A","explanation":"Given: The uniform velocity of the car = 30ms-1  The frictional force, FR = 600N  Recall: Power = Force \u00d7 Velocity  \u2234 P = 600 \u00d7 30 = 18000W = 18KW.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>7","subject":"Physics","year":"2008","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"A rectangular block of dimensions 2.0m \u00d7 1.0m \u00d7 0.5m weighs 200N. Calculate the maximum pressure exerted by the block on a horizontal floor.","images":[],"options":{"A":"100Nm-2","B":"200Nm-2","C":"300Nm-2","D":"400Nm-2"},"answer":"A","explanation":"Given: The dimension of the block = 2.0m \u00d7 1.0m \u00d7 0.5m  The weight, W of the block = 200N  The maximum pressure, Pmax = ?  Recall that: Pressure,P=ForceArea  The maximum pressure will be exerted when the block is occupying its maximum area on the floor.  The maximum area of the block = 2 \u00d7 1 = 2m2  \u2234Pmax=2002=100Nm-2","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>8","subject":"Physics","year":"2008","type":"Objective","topic":"MOTION : TYPES OF MOTION","question":"The diagram above represents the displacement-time graph of the motion of an object thrown upwards. The velocity of the object at the point P is","images":["data:image/png;base64,"],"options":{"A":"maximum","B":"uniform","C":"zero","D":"terminal"},"answer":"C","explanation":"At point P, the object has reached its maximum height where the velocity is equal to zero.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>9","subject":"Physics","year":"2008","type":"Objective","topic":"GRAVITATIONAL FIELD : ACCELERATION DUE TO GRAVITY","question":"A very sensitive spring balance was used to determine the weight of an object at the north pole. When the same spring balance was used to measure the weight of the same object at the equator, it was found to reduce. The explanation for this observation is that","images":[],"options":{"A":"it is very hot at the equator","B":"the spring balance has expanded","C":"the acceleration of free fall due to gravity varies with location","D":"the mass of the body is reduced"},"answer":"C","explanation":"It should be noted that Weight, W = mass, m \u00d7 acceleration due to gravity, g  \u2234 W = mg  'g' varies from place to place. (it is usually greater at the pole than at the equator).","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>10","subject":"Physics","year":"2008","type":"Objective","topic":"SCALARS AND VECTORS : RESULTANT VELOCITY","question":"A ship moving northward with speed Vs is acted upon by a wind blowing the due west at a speed Vw. Which of the following diagrams correctly indicates the velocity VR of the wind relative to the ship?","images":["data:image/png;base64,","data:image/png;base64,","data:image/png;base64,","data:image/png;base64,"],"options":{"A":"","B":"","C":"","D":""},"answer":"A","explanation":"Given: The northward speed, Vc  The speed of the wind, Vw  The resultant speed = VR","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>11","subject":"Physics","year":"2008","type":"Objective","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"The diagram above shows three forces F1, F2 and F3 which keep the bar AB in horizontal equilibrium. Which of the following equations is correct?","images":["data:image/png;base64,"],"options":{"A":"F3 = F1 + F2","B":"F2 = F1 + F3","C":"F1 = F2 - **F3","D":"F1 = F2 + F3"},"answer":"D","explanation":"Given: The diagram in the question    It should be noted that if a body is in equilibrium under the action of parallel forces, the total upward force = total downward force.  Therefore, F3 + F2 = F1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>12","subject":"Physics","year":"2008","type":"Objective","topic":"MOTION : SIMPLE IDEAS OF CIRCULAR MOTION","question":"A mass attached to a string is moving in a circular path. If the speed is doubled, the tension in the string will be","images":[],"options":{"A":"doubled","B":"halved","C":"four times as great","D":"one-fourth as much"},"answer":"C","explanation":"Given: Initial speed = V1  Final speed = V2 = 2V1  Initial tension = T1  Final tension = T2 = ?  It should be noted that: V \u03b1 &radic;T&nbsp;  \u2234 V = K&radic;T&nbsp;   V&radic;T&nbsp;=K  V1&radic;T1&nbsp;=V2&radic;T2&nbsp;  V1&radic;T1&nbsp;=2V1&radic;T2&nbsp;:1&radic;T1&nbsp;  =2&radic;T2&nbsp;:&radic;T2T1&nbsp;=21  T2T1=(2)2  T2T1=41  T2 = 4T1","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>13","subject":"Physics","year":"2008","type":"Objective","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"An object of mass 2kg moving with a velocity of 3ms-1 collides head-on with another object of mass 1kg moving in the opposite direction with a velocity 4ms-1. If the objects stick together after collision, calculate their common speed.","images":[],"options":{"A":"0.60ms-1","B":"0.67ms-1","C":"2.00ms-1","D":"3.33ms-1"},"answer":"B","explanation":"Given: m1 = 2kg ; m2 = 1kg  v1 = 3ms-1 ; v2 = 4ms-1  Common velocity, V is unknown  Recall: m1v1 + m2v2 = (m1 + m2)V  V=m1v1+m2v2m1+m2(Iftheyaremovinginthesamedirectionalbeforecollision)  Also, m1v1 - m2v2 = (m1 + m2)v  v=m1v1 - m2v2m1 + m2  v=6 - 43=23=0.67ms-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>14","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC ENERGY AND POWER","question":"Which of the following devices converts heat energy to electrical energy?","images":[],"options":{"A":"Transformer","B":"Dynamo","C":"Thermocouple","D":"Thermostat"},"answer":"C","explanation":"A thermocouple is a device that converts heat energy into electrical energy by exploiting the Seebeck effect, where a voltage is produced by a temperature difference between two different metals.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>15","subject":"Physics","year":"2008","type":"Objective","topic":"WORK, ENERGY AND POWER : TYPES OF MECHANICAL ENERGY: POTENTIAL ENERGY AND KINETIC ENERGY","question":"A ball is dropped and it hits the floor at a point A. It rebounds upwards to a point B. While moving from A to B its","images":[],"options":{"A":"kinetic energy is increasing","B":"potential energy is increasing","C":"potential energy is decreasing","D":"kinetic energy  remains constant"},"answer":"B","explanation":"The information can be represented diagrammatically as:    From A to B the height is decreasing such that h4 = 0.  \u2234 Potential energy at B (h4 = 0) = mg(0) = 0.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>16","subject":"Physics","year":"2008","type":"Objective","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"An object of mass 0.25kg moves at a height h above the ground with a speed of 4ms-1. If its mechanical energy at this height is 12 J, determine the value of h. [g = 10ms-1]","images":[],"options":{"A":"0.8m","B":"4.0m","C":"4.8m","D":"5.6m"},"answer":"B","explanation":"Given: Mass of object, m = 0.25kg  Height, h above the ground = h  Speed, v = 4ms-1.  The mechanical energy, M.E at h = 12J  \u2192 It should be noted that M.E = P.E + K.E  \u223412=mgh+12  mv2  12=m(gh+v22)  12=0.25(10h+162)  12 = 0.25(10h + 8)  12 = 2.5h + 2  10 = 2.5h  h = 4m","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>17","subject":"Physics","year":"2008","type":"Objective","topic":"MACHINES :","question":"Which of the following equations for the efficiency of a machine is correct?","images":[],"options":{"A":"Efficiency=Velocity RatioMechanical Advantage\u00d7100%","B":"Efficiency=InputOutput\u00d7100%","C":"Efficiency=Load distanceEffort distance\u00d7100%","D":"Efficiency=Mechanical AdvantageVelocity Ratio\u00d7100%"},"answer":"D","explanation":"The efficiency of a machine is given by the ratio of the Mechanical Advantage to the Velocity Ratio, multiplied by 100%. The Mechanical Advantage is the ratio of the output force (load) to the input force (effort), and the Velocity Ratio is the ratio of the distance moved by the effort to the distance moved by the load. Therefore, the correct equation for the efficiency of a machine is Efficiency = (Mechanical Advantage / Velocity Ratio) * 100%, which matches option 4.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>18","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"The design of the thermostat of an electric iron is based on the","images":[],"options":{"A":"emission of electrons from metals when heated","B":"increase in size of metals when heated","C":"increase in the density of metals when heated","D":"change in the mass of metals when heated"},"answer":"B","explanation":"The design of the thermostat is based on the increase in size of metals when heated.    Such that: T2 > T1.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>19","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : THERMAL EXPANSION","question":"A metal rod of length 50cm is heated from 40\u00b0C to 80\u00b0C. If the linear expansivity of the material is \u03b1, calculate the increase in length of the rod (in metres) in terms of \u03b1.","images":[],"options":{"A":"20 \u03b1","B":"200 \u03b1","C":"2000 \u03b1","D":"20000 \u03b1"},"answer":"A","explanation":"Given:  The initial length, L1 = 50cm = 0.5m  The initial temperature, \u03b81 = 40\u00b0c  The final temperature, \u03b82 = 80\u00b0c  The linear expansivity = \u03b1  The increase in length, \u0394L = ?  Recall:\u03b1=\u0394LL1(\u0394\u03b8)  Also recall:\u03b1=\u0394L0.5(40)  \u03b1=\u0394L2000  \u2234 \u0394L = 20\u03b1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>20","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : GAS LAWS","question":"The cubic expansivity of a certain gas at a constant pressure is 1/273 K-1.  If a given mass of the gas is held at constant pressure and its volume at 0oC is 273m3, determine the volume of the gas at 273\u00b0C.","images":[],"options":{"A":"273m3","B":"546m3","C":"819m3","D":"1092m3"},"answer":"B","explanation":"Given: The cubic expansivity, \u03b3 of the gas = 1/273 k-1  The pressure, P is constant; i.e P1 = P2  Volume, V1 = 273m3 at 0\u00b0c = 273k  Volume, V2 = ? at 273\u00b0c = 546k  The two notable parameters are: volume and temperature  Recall:V1T1=V2T2  273273=V2546  \u2234 V2 = 546cm3","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>21","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : HEAT CAPACITY","question":"Water mass 1.5kg is heated from 30\u00b0C to 80\u00b0C using an electric kettle which is rated 5A, 230V. Calculate the time taken to reach the final temperature.  [Specific heat capacity of water = 4200 Jkg-1K-1]","images":[],"options":{"A":"4.57 minutes","B":"5.02 minutes","C":"7.30 minutes","D":"10.04 minutes"},"answer":"A","explanation":"Given: The mass, m of water = 1.5kg  The temperature change = 80\u00b0c - 30\u00b0c = 50\u00b0c  Electric current, I = 5A  Voltage, V = 230V  SHC of water = 4200Jkg-1k-1  It should be noted that: The electrical energy released by the heater = The heat energy absorbed by water.  \u2234 Ivt = mc\u0394\u03b8  5 \u00d7 230 \u00d7 t = 1.5 \u00d7 4200 \u00d7 50  1150t = 315,000  t=3150001150=630023\u2248274seconds=4.57minutes","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>22","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"The working principle of a pressure cooker is based on the","images":[],"options":{"A":"increase in the volume of steam inside it","B":"complete trapping of heat inside it","C":"increase in the pressure of the pot","D":"decrease in the pressure of the pot"},"answer":"C","explanation":"A pressure cooker works by increasing the pressure inside the pot. This increase in pressure raises the boiling point of the water inside the cooker, allowing the food to cook at a higher temperature and therefore cook faster. This matches option 3.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>23","subject":"Physics","year":"2008","type":"Objective","topic":"HEAT ENERGY : BOILING POINT","question":"It takes a shorter time for a liquid to boil at the top of a mountain than at the base because at the top, the","images":[],"options":{"A":"temperature is higher","B":"pressure is lower","C":"humidity is higher","D":"temperature is constant"},"answer":"B","explanation":"It should be noted that, the higher the height, the lower the atmosphere pressure and the lower the boiling point.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>24","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"Light is considered as a transverse wave because it travels","images":[],"options":{"A":"through materials without causing disturbance of the medium","B":"through space with constant speed","C":"in a direction parallel to the plane containing the electric and magnetic fields","D":"in a direction perpendicular to the plane containing the electric and magnetic fields."},"answer":"D","explanation":"Transverse wave possess particles which travel perpendicular to that of the energy propagated by the wave. It should be noted that the energy propagated by the wave is electromagnetic in nature.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>25","subject":"Physics","year":"2008","type":"Objective","topic":"GRAVITATIONAL FIELD : NEWTON\u2019S LAW OF GRAVITATION","question":"Thediagramaboveillustratesthesun,moonandearthinthesamestraightlineduringaneclipse. An observer at the point P on earth observes.","images":["data:image/png;base64,"],"options":{"A":"annular eclipse","B":"partial eclipse","C":"total eclipse","D":"no eclipse"},"answer":"A","explanation":"Annular eclipse is formed when the distance between the sun and the moon is such that the umbra cone of the moon's shadow ends above the surface of the earth. This occurs when the angular diameter of the sun as observed from the earth is greater than that of the moon.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>26","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : PLANE MIRROR","question":"The letter F is placed in front of a plane mirror as illustrated in the diagram beside.    Which of the following represents the image observed?","images":["data:image/png;base64,","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAACQAAAA5CAAAAAB7I9YBAAAAB3RJTUUH4QMUFBg61i+S2AAAAHFJREFUSIntlc0OgDAIg6nx/V8ZD27+hG52elHDTix8g4aSDG7XZxKYhMzm4wU18A7Uosc1tXwcFx6qAU4h9uKNtnwOApRKZeLMFhRg26oAIQR3hTvZPKJpp2rH53NyBZIqJfQzCHZabQqx/JrIT1GCFtzfDn/HJDnQAAAAAElFTkSuQmCC","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAACUAAAA0CAAAAAAof67hAAAAB3RJTUUH4QMUFBkG4FvfHgAAAH1JREFUOI3tleEKwCAIhHfh+7+y+7ORZtltEASbfwr88pQTgh5EFAbalpL7gpAy06/oKxWsfV0JaO+NGKIe2mDFQ5O+fLSKu/q4hIoWPa5VfURigHN7qPp+xigsvaS22qUDJYoOojdHKYqr9VO7U5hSYf/HiqAou2D4wJ92AhYJEm+78EbaAAAAAElFTkSuQmCC","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAB8AAAAyCAAAAACB918NAAAAB3RJTUUH4QMUFBkgMlZa4wAAAHlJREFUOI3tk8EOgCAMQzvi///yvBDZtFumYrjIhYTHWjpAFOloOV7Otz4LAOAaxtWTrC1GJX/Lmcbq/vz8IZecd3y8P7s2xZ/oj/c1nHi9as65vlM41bNsFf0qn/H/3vAoX9AfQT9yfP96xz+yh7jGmG3KeKj/Gd8BU9sPaqDeLZkAAAAASUVORK5CYII=","data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAB0AAAAyCAAAAACFAo8wAAAAB3RJTUUH4QMUFBkrpYSDawAAAGtJREFUOI3dlNEKwCAIRb1j///Lt4dRM/C6oIiYT8GhY6IJWhJXBldToB3v6ArMjJmZyuxq3FrRPyk35UVKRdTJgfERMKJN3uWYeXM1+3SvfMgsfuJh3V9FIdr70X0whDMzCU/VOsQ5e3KYFpgCDWt5j3aWAAAAAElFTkSuQmCC"],"options":{"A":"","B":"","C":"","D":""},"answer":"B","explanation":"The process (phenomenon) illustrated is  Lateral Inversion .","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>27","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"In the day time, it is possible to see under shady areas such as under a tree, because light has undergone","images":[],"options":{"A":"internal reflection","B":"refraction","C":"diffraction","D":"diffuse reflection"},"answer":"D","explanation":"During the day, we can see under shady areas such as under a tree because light has undergone diffuse reflection. Diffuse reflection is the reflection of light in many directions by a rough surface. The leaves and branches of the tree scatter the light in many directions, allowing us to see under the tree.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>28","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"The distance between a concave mirror and a object placed in front of it is 1.0m. If the radius of curvature of the mirror is 4.0m, the image formed will be","images":[],"options":{"A":"2.00m behind the mirror","B":"2.00m in front of the mirror","C":"1.25m in front of the mirror","D":"1.25m behind the mirror"},"answer":"A","explanation":"Recall:   1v=1f-1u  v = image distance, u = object distance; f = focal length  f=(Radius)2  f=r2  Given: v = ? u = 1.0m   f=42=2m  1v=12-11  1v=-12  v = -2","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>29","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"The image of an object formed by a convex mirror is","images":[],"options":{"A":"real, erect and enlarged","B":"real, inverted and enlarged","C":"virtual, erect and diminished","D":"virtual, erect and enlarged"},"answer":"C","explanation":"The image formed by a convex mirror is usually virtual i.e it is formed at the back of the mirror. The image formed by a convex mirror is erect, i.e it stands upright upon forming. The image formed by a convex mirror is also diminished, i.e it is usually smaller than the object.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>30","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : REFRACTION OF LIGHT AT PLANE SURFACES","question":"When viewed straight down, a fish in a pond is","images":[],"options":{"A":"farther below than it appears to be","B":"nearer than it appears to be","C":"found at exactly the same point it is seen","D":"seen beside its large"},"answer":"A","explanation":"Due to refraction, a fish in a pond appears to be closer to the surface than it actually is. This is because light rays from the fish bend away from the normal as they move from a denser medium (water) to a less dense medium (air), causing the fish to appear to be at a shallower depth. So, the fish is actually farther below but it appears to be closer to the surface.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>31","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"A converging lens and a screen are placed 20cm and 80cm respectively from an object in a straight line so that a sharp image of the object is formed on the screen. If the object is 3cm high, calculate the height of the image formed.","images":[],"options":{"A":"1cm","B":"9cm","C":"12cm","D":"15cm"},"answer":"B","explanation":"Recall:vu=HiHo  u = object distance, v = image distance, Hi = image height, Ho = object height  \u22346020=Hi3  31=Hi3  \u2234 Hi = 9cm.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>32","subject":"Physics","year":"2008","type":"Objective","topic":"LIGHT WAVES : APPLICATION OF LENSES IN OPTICAL INSTRUMENTS","question":"Which of the following defects of vision is as a result of the eye ball being too long?","images":[],"options":{"A":"Long sight","B":"Astigmatism","C":"Short sight","D":"Loss of accommodation"},"answer":"C","explanation":"The short sightedness is as a result of the eye ball being too long such that rays from distant objects are brought to a focus in front of the retina instead of at the retina","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>33","subject":"Physics","year":"2008","type":"Objective","topic":"SOUND WAVES : ECHOES AND REVERBERATION","question":"A sound wave is produced from a source and an echo is heard t seconds afterwards. If d is the distance of the reflecting surface from the source, v the speed, \u03bb the wavelength and T the period of the wave, then","images":[],"options":{"A":"d=2t\u03bb","B":"d=\u03bbt2T","C":"d=2T\u03bbt","D":"d=\u03bbTt"},"answer":"B","explanation":"When a sound is produced, the sound heard by the source immediately after the sound is produced is the echo.    \u2234V=2dt  Recall; V = f\u03bb  \u2234f\u03bb=2dt  f\u03bbt = 2d  d=f\u03bbt2  Also,F=1T  \u2234d=f\u03bbt2becomes  d=\u03bbt2T","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>34","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"A negatively charged rod is held close to an uncharged metal ball on an insulating stand. The ball will","images":[],"options":{"A":"be negatively charged","B":"be positively charged","C":"have an excess of negative charges on the side nearest the rod","D":"have an excess of positive charges on the side nearest the rod"},"answer":"D","explanation":"When a negatively charged rod is held close to an uncharged metal ball on an insulating stand, the ball will have an excess of positive charges on the side nearest the rod.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>35","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : COULOMB\u2019S LAW","question":"Two bodies each carrying a charge of 2.00 \u00d7 10-10 C are 5cm apart. Calculate the magnitude of the force between the charges.  [1/4\u03c0\u03b5o  =  9 \u00d7 10\u2079Nm\u00b2/C\u00b2]","images":[],"options":{"A":"1.44 \u00d7 10-7 N","B":"7.20 \u00d7 10-9 N","C":"7.20 \u00d7 10-11 N","D":"1.44 \u00d7 10-11 N"},"answer":"D","explanation":"Given: - charge, q1 = q2 = 2 \u00d7 10-10C  - the distance between the two charges = 5cm =0.05m  - the magnitude of force, F is unknown.    Recall:F=Kq1q2d2(coloumb'slaw)  \u2234F=k(2\u00d710-10\u00d72\u00d710-10)(0.05)2=k(4\u00d710-20)0.0025   = k \u00d7 0.16 \u00d7 10-16    = 9 \u00d7 109 \u00d7 0.16 \u00d7 10-16    = 1.44 \u00d7 10-7N","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>36","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : PRODUCTION OF ELECTRIC CHARGES","question":"If the charge on an object is measured as 4.0 \u00d7 10-10 C, how many excess electrons does the object possess, given that the charge of an electron is 1.6 \u00d7 10-19C?","images":[],"options":{"A":"18","B":"19","C":"25","D":"37"},"answer":"C","explanation":"Given: (1) The charge on the object = 4.0 \u00d7 10-18c  (2) The charge of an electron = 1.6 \u00d7 10-19c  Recall:Excesselectron=Charge on the object Charge of electron  \u2234Excesselectron=4.0\u00d710-181.6\u00d710-9   = 2.5 \u00d7 10 = 25","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>37","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CURRENT, POTENTIAL DIFFERENCE, RESISTANCE, E.M.F. AND INTERNAL RESISTANCE","question":"Which of the following is a unit of the time rate of flow of electric charges?","images":[],"options":{"A":"Coulomb","B":"Ampere","C":"Volt","D":"Watt"},"answer":"B","explanation":"- The time rate of flow of electric charges = Current  That is, ChargeTime=Current  \u2234CoulombSecond=Ampere  Coulomb is the S.I unit of charge, second is the S.I unit of time and Ampere is the S.I unit of current.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>38","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : RESISTIVITY AND CONDUCTIVITY","question":"A wire, 1.0m long and with cross-sectional area 2.0 \u00d7 10-7 m2 has a resistance of 0.1\u03a9. Calculate the electrical conductivity of the wire.","images":[],"options":{"A":"2.0 \u00d7 107 \u03a9-1m-1","B":"5.0 \u00d7 107\u03a9-1m-1","C":"2.0 \u00d7 108\u03a9-1m-1","D":"5.0 \u00d7 108\u03a9-1m-1"},"answer":"B","explanation":"Given:  (1) The length of the wire, l = 1.0m  (2) Area of cross-section, A = 2 \u00d7 10-7m2  (3) Resistance, R = 0.1\u03a9  (4) Electrical conductivity is unknown.  Recall: R = \u03c1/A : P is the electrical resistivity.  It should be noted that;   Theelectricalconductivity=1\u03c1  \u22340.1=\u03c1\u00d71.02\u00d710-7  Electricalconductivity=12\u00d710-8=12\u00d7108\u03a9-1m-1  = 0.5 \u00d7 108 \u03a9-1m-1   = 5 \u00d7 107\u03a9-1m-1","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>39","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : CAPACITANCE, ARRANGEMENT AND APPLICATION","question":"Three capacitors each of capacitance 1.5\u00b5F are connected in series. The total capacitance in the circuit is","images":[],"options":{"A":"2.0\u00b5F","B":"1.5\u00b5F","C":"0.6\u00b5F","D":"0.5\u00b5F"},"answer":"D","explanation":"Given: (1) The value of the capacitance of each capacitor = 1.5\u00b5F  Recall: if capacitance of capacitors are arranged in series, the total resistance, CT is given as: 1CT=1C1+1C2+1C3......+1Cn  \u22341CT=11.5+11.5+11.5  1CT=31.5  CT=1.53=12=0.5\u00b5F","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>40","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : POTENTIAL DIFFERENCE AND ELECTRIC CURRENT","question":"A voltmeter is a device that","images":[],"options":{"A":"draws high current","B":"has a very low resistance","C":"has a very high resistance","D":"is able to measure both voltage and current"},"answer":"C","explanation":"A voltmeter is a device that is used to measure the voltage difference between two points in an electrical circuit. It has a very high resistance so that it does not draw current from the circuit and alter the voltage it is measuring. Therefore, the correct answer is 'has a very high resistance'.","marks":"1","difficulty":"1"},{"id":"objective>Physics>2008>41","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTRIC FIELD : ELECTRIC CIRCUIT","question":"Which of the following actions will not increase the sensitivity of a moving coil galvanometer?","images":[],"options":{"A":"Using a strong temporary magnet","B":"Increasing the area and number of turns of the coil","C":"Using a weak hair spring","D":"Using a light pointer"},"answer":"A","explanation":"The sensitivity of a moving coil galvanometer can be increased by increasing the area and number of turns of the coil, using a weak hair spring, and using a light pointer. However, using a strong temporary magnet will not increase the sensitivity. Moving coil galvanometer uses a permanent magnet.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>42","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTROMAGNETIC FIELD : MOTOR-GENERATOR EFFECT","question":"Fleming's right hand rule is also called the","images":[],"options":{"A":"motor rule","B":"dynamo rule","C":"screw rule","D":"thumb rule"},"answer":"B","explanation":"Fleming's right hand rule is also called the dynamo rule.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>43","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"A transformer is required to supply 12Vrms to operate a toy train set from a 240Vrms. If the number of turns in the secondary coil is 100, calculate the number of turns required in the primary coil.","images":[],"options":{"A":"5","B":"12","C":"2000","D":"2400"},"answer":"A","explanation":"Given: Primary voltage = 12  Secondary voltage = 240  Number of turns in the secondary coil = 100  Number of turns in the primary coil = ?  Recall:EsEp=NsNp  \u223424012=100x  201=100x  x = 5","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>44","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTROMAGNETIC FIELD : FARADAY\u2019S LAW","question":"The diagram above illustrates a bar magnet near a coil connected to a galvanometer. When the magnet is rapidly moved towards the coil  I. an e.m.f is induced in the coil.  II. the galvanometer needle deflects.  III. the magnet is attracted.    Which of the statements above are correct?","images":["data:image/png;base64,"],"options":{"A":"I and II only","B":"II and III only","C":"I and III only","D":"I, II and III"},"answer":"A","explanation":"When the magnet is moved towards the galvanometer, an e.m.f is usually induced in the coil and this causes the pointer to deflect.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>45","subject":"Physics","year":"2008","type":"Objective","topic":"ELECTROMAGNETIC FIELD : INDUCTANCE","question":"A direct current of 5A flows through a 0.2H inductor, Calculate the energy stored in the inductor.","images":[],"options":{"A":"0.5J","B":"1.0J","C":"2.5J","D":"5.0J"},"answer":"D","explanation":"Given: (1) Inductance, L = 0.2H  (2) Current, I = 5A  (3) Power, P = ?  (4) Energy = ?  Recall: P = I2L  P = 52 \u00d7 0.2 = 5W  \u2234 Energy = 5J","marks":"1","difficulty":"3"},{"id":"objective>Physics>2008>46","subject":"Physics","year":"2008","type":"Objective","topic":"STRUCTURE OF THE ATOM : X-RAYS","question":"Both \u03b3 rays and X-rays  I. can be produced by thermionic emission  II. have low frequencies  III, have short wavelengths    Which of the statements above is/are correct?","images":[],"options":{"A":"I only","B":"II only","C":"III only","D":"I and III only"},"answer":"C","explanation":"\u03b3 rays and X-rays are both forms of electromagnetic radiation. They are not produced by thermionic emission (statement I is incorrect) and they do not have low frequencies (statement II is incorrect). They do, however, have short wavelengths (statement III is correct). Therefore, the correct answer is III only.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>47","subject":"Physics","year":"2008","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"When a radioactive substance undergoes a beta decay, its","images":[],"options":{"A":"mass number decreases by 1","B":"atomic number decreases by 1","C":"mass number increases by 1","D":"atomic number increases by 1"},"answer":"D","explanation":"abX \u2192 ab+1P + 0-1e (Beta particle)  The atomic number of the resulting atom will increase by one.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>48","subject":"Physics","year":"2008","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Nuclear fission is preferred to nuclear fusion in the generation of energy because","images":[],"options":{"A":"very high temperatures are required for fusion","B":"the raw materials for fusion are easily obtained","C":"energy obtained from fusion is relatively smaller","D":"the by-products of fusion are very dangerous"},"answer":"A","explanation":"Nuclear fusion requires very high temperatures (in the order of millions of degrees) to overcome the electrostatic repulsion between the positively charged nuclei that are to be fused together. This makes it technically challenging to achieve and control, which is why nuclear fission is currently preferred for energy generation.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>49","subject":"Physics","year":"2008","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Control in nuclear reactors is effected with boron rods because the rods have the ability to","images":[],"options":{"A":"absorb electrons","B":"absorb neutrons","C":"accelerate electrons","D":"slow down neutrons"},"answer":"B","explanation":"Control rods in nuclear reactors are used to absorb neutrons, which slows down the nuclear chain reaction. Boron is one of the materials commonly used for this purpose because it has a high cross-section for neutron absorption, meaning it is very likely to absorb neutrons when they pass through it.","marks":"1","difficulty":"2"},{"id":"objective>Physics>2008>50","subject":"Physics","year":"2008","type":"Objective","topic":"STRUCTURE OF THE NUCLEUS : RADIOACTIVITY","question":"A radioactive element has a decay constant of 0.077s-1. Calculate its half-life.","images":[],"options":{"A":"13.0s","B":"9.0s","C":"5.1s","D":"0.5s"},"answer":"B","explanation":"Given: (1) The decay constant, \u03bb = 0.077s-1  (2) The half-life, t1/2 = ?  Recall;t1/2=0.693\u03bb  t1/2=0.6930.077=9s","marks":"1","difficulty":"3"}];